            mask_to_adj_matrix_small_N(mask_to_print, N_ACTUAL, temp_adj_cstyle);
            for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) G_ADJS_CHOSEN_GED[k_idx][r][c] = temp_adj_cstyle[r][c];

