            for (int e = 0; e < E_k; ++e) {
                int u = lex_edges[e].first;
                int v = lex_edges[e].second;
                G_ADJ_LARGE[k][u][v] = true;
                G_ADJ_LARGE[k][v][u] = true;
                G_DEGREES_LARGE[k][u]++;
                G_DEGREES_LARGE[k][v]++;
