                        h_degrees[j]++;
                    }
                }
            }

            // Sort H vertices by degree (descending), ties by index
            std::vector<int> h_degree_order(N_ACTUAL);
            std::iota(h_degree_order.begin(), h_degree_order.end(), 0);
            std::sort(h_degree_order.begin(), h_degree_order.end(),
                [&](int a, int b) {
                    if (h_degrees[a] != h_degrees[b])
                        return h_degrees[a] > h_degrees[b];
                    return a < b;
                });

            // For each G_j, compute approximate GED using degree-based alignment
            int best_g_idx = 0;
            int min_diff = L_ACTUAL + 1;

            for (int j = 0; j < M_graphs; ++j) {
                int diff = compute_approx_ged(h_degree_order, j);
                if (diff < min_diff) {
                    min_diff = diff;
                    best_g_idx = j;
                }
            }

            std::cout << best_g_idx << std::endl;
        }
        std::cout.flush();
    }
    return 0;
}
