                }
            }

            // Sort descending
            std::sort(h_degrees.begin(), h_degrees.end(), std::greater<int>());

            // For each G_k, compute expected sorted degree sequence under noise
            // and find the one with minimum L2 distance to H's sorted degree sequence.
            //
            // Expected degree of vertex with true degree d: d*(1-2*eps) + (N-1)*eps
            // Expected sorted degree sequence: apply this transform to G_k's sorted degrees
            // (valid approximation when degrees are well-separated)

            int best_g_idx = 0;
            double min_dist = 1e18;

            double scale = 1.0 - 2.0 * eps;
            double offset = (N_ACTUAL - 1) * eps;

            for (int j = 0; j < M_graphs; ++j) {
                double dist = 0.0;
                for (int i = 0; i < N_ACTUAL; ++i) {
                    double expected_deg = G_SORTED_DEGREES[j][i] * scale + offset;
                    double diff = h_degrees[i] - expected_deg;
                    dist += diff * diff;
                }
                if (dist < min_dist) {
                    min_dist = dist;
                    best_g_idx = j;
                }
            }

            std::cout << best_g_idx << std::endl;
        }
        std::cout.flush();
    }
