            if (M_graphs == 0) { std::cout << 0 << std::endl; std::cout.flush(); continue; }

            string_to_adj_matrix_query(h_str, N_ACTUAL);

            // Compute degree sequence of H
            std::vector<int> h_degrees(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) {
                        h_degrees[i]++;
                        h_degrees[j]++;
                    }
                }
            }

            // Sort H vertices by degree (descending), ties by index
            std::vector<int> h_degree_order(N_ACTUAL);
            std::iota(h_degree_order.begin(), h_degree_order.end(), 0);
            std::sort(h_degree_order.begin(), h_degree_order.end(),
                [&](int a, int b) {
                    if (h_degrees[a] != h_degrees[b]) return h_degrees[a] > h_degrees[b];
                    return a < b;
                });

            // First pass: use sorted degree sequence for pre-filtering
            // Get sorted H degrees
            std::vector<int> h_sorted_degrees = h_degrees;
            std::sort(h_sorted_degrees.begin(), h_sorted_degrees.end(), std::greater<int>());

            double scale = 1.0 - 2.0 * eps;
            double offset = (N_ACTUAL - 1) * eps;

