        if (min_dist == 0) break;

        ops_count++;
        if (ops_count >= N_factorial) break;
    } while (std::next_permutation(P_VERTS_PERM_QUERY.begin(), P_VERTS_PERM_QUERY.end()));

    return min_dist;
}

