        } else {
            // SORTED_DEGREE_SEQ + approximate GED strategy
            if (M_graphs == 0) { std::cout << 0 << std::endl; std::cout.flush(); continue; }

            string_to_adj_matrix_query(h_str, N_ACTUAL);

            // Compute degree sequence of H
            std::vector<int> h_degrees(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) {
                        h_degrees[i]++;
                        h_degrees[j]++;
                    }
                }
            }

            // Sort H vertices by degree (descending), ties by index
            std::vector<int> h_degree_order(N_ACTUAL);
            std::iota(h_degree_order.begin(), h_degree_order.end(), 0);
            std::sort(h_degree_order.begin(), h_degree_order.end(),
                [&](int a, int b) {
                    if (h_degrees[a] != h_degrees[b]) return h_degrees[a] > h_degrees[b];
                    return a < b;
                });

            // First pass: use sorted degree sequence for pre-filtering
            // Get sorted H degrees
            std::vector<int> h_sorted_degrees = h_degrees;
            std::sort(h_sorted_degrees.begin(), h_sorted_degrees.end(), std::greater<int>());

            double scale = 1.0 - 2.0 * eps;
            double offset = (N_ACTUAL - 1) * eps;

            // Find top candidates by sorted degree L2 distance
            std::vector<std::pair<double, int>> candidates;
            for (int j = 0; j < M_graphs; ++j) {
                double dist = 0.0;
                for (int i = 0; i < N_ACTUAL; ++i) {
                    double expected_deg = G_SORTED_DEGREES[j][i] * scale + offset;
                    double diff = h_sorted_degrees[i] - expected_deg;
                    dist += diff * diff;
                }
                candidates.push_back({dist, j});
            }
            std::sort(candidates.begin(), candidates.end());

            // For top candidates, compute approximate GED using degree-rank alignment
            int num_detailed = std::min((int)candidates.size(), std::min(M_graphs, 5));

            int best_g_idx = candidates[0].second;
            int min_edge_diff = L_ACTUAL + 1;

            for (int c = 0; c < num_detailed; ++c) {
                int j = candidates[c].second;
                const auto& g_order = G_DEGREE_ORDER_LARGE[j];

                // Build mapping: h_degree_order[r] -> g_order[r]
                // i.e., h vertex ranked r maps to g vertex ranked r
                std::vector<int> h_to_g(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r) {
                    h_to_g[h_degree_order[r]] = g_order[r];
                }

                int diff = compute_edge_diff_with_mapping(h_to_g, j);
                if (diff < min_edge_diff) {
                    min_edge_diff = diff;
                    best_g_idx = j;
                }

                // Also try a few random shuffles within same-degree groups
                // For threshold graphs, groups are: hub vertices (degree N-1) and non-hub (degree k)
                // Shuffling within groups doesn't change the edge diff for threshold graphs.
                // So degree-rank alignment is already optimal for threshold graphs.
            }

