        // After noise: expected degree of hub = (N-1)*(1-2eps) + (N-1)*eps = (N-1)*(1-eps)
        // Expected degree of non-hub in graph k = k*(1-2eps) + (N-1)*eps
        // Difference between a non-hub in graph k+1 and graph k: (1-2*eps)
        // Std dev of any vertex degree: sqrt((N-1)*eps*(1-eps))
        //
        // The main confusion is between graphs k and k+1.
        // With N independent degree measurements (sorted), the effective signal-to-noise:
        // Signal = sum of squared differences in expected sorted degrees between G_k and G_{k+1}
        // For threshold: diff between sorted degs of G_k and G_{k+1} is:
        //   position k: (N-1) vs k+1 (hub vs non-hub), difference = N-1-(k+1) = N-k-2
        //   After noise scaling: (N-k-2)*(1-2*eps)
        // Variance of each sorted degree position ~ (N-1)*eps*(1-eps)
        // For L2 squared distance: signal^2 / variance = ((N-k-2)*(1-2*eps))^2 / ((N-1)*eps*(1-eps))
        //
        // Worst case is k = N-3 (smallest separation): signal = 1*(1-2*eps)
        // But actually worst case for M graphs is k around M/2.
        // The minimum separation between adjacent threshold graphs in sorted-degree L2:
        // It occurs for graphs with many hubs where the new hub's degree doesn't differ much.
        //
        // Simplified: use the average-case error approximation.
        // For adjacent pairs, squared L2 distance ~ ((N-1)*(1-2*eps))^2 + smaller terms
        // Noise variance of L2 ~ N * (N-1)*eps*(1-eps)
        // Chi-squared test: d^2 / variance_sum

        // Approximation: P(error) ≈ erfc(signal / (sqrt(2) * noise))
        // where signal = (N-1)*(1-2*eps), noise_std = sqrt(N*(N-1)*eps*(1-eps))
        // For the WORST adjacent pair (minimum separation):
        double signal_sq = (double)(N-1) * (1.0 - 2.0*eps) * (N-1) * (1.0 - 2.0*eps);
        double noise_var = (double)N * (N-1) * eps * (1.0 - eps);
        double snr = signal_sq / noise_var;

        // P(error for one pair) ≈ erfc(sqrt(snr/2)) / 2
        double p_err_pair = 0.5 * std::erfc(std::sqrt(snr / 2.0));

        // With M-1 adjacent pairs, expected errors per 100 queries ≈ 100 * p_err_pair * (M-1) / M
        // (simplified: each query has p_err_pair chance of confusing with nearest neighbor)
        double p_err_query = std::min(1.0, p_err_pair * 2.0); // factor 2 for both neighbors
        double E_expected = 100.0 * p_err_query;

        double score = std::pow(0.9, E_expected) / N;
        if (score > best_score) {
            best_score = score;
            best_N = N;
        }
    }

    return best_N;
}

