int compute_N_for_threshold(int M, double eps) {
    if (M <= 1) return 4;
    if (eps < 1e-9) return std::max(4, M);

    // Use K=3.0 formula (proven to work well)
    double K = 3.0;
    double L_needed = K * K * (double)(M - 1) * (M - 1) * eps * (1.0 - eps);
    double discriminant = 1.0 + 8.0 * L_needed;
    int N_candidate;
    if (discriminant >= 0) {
        N_candidate = (int)std::ceil((1.0 + std::sqrt(discriminant)) / 2.0);
    } else {
        N_candidate = 100;
    }
    // Ensure N >= M for threshold construction
    N_candidate = std::max(N_candidate, M);
    return std::max(4, std::min(100, N_candidate));
}

