147	int compute_N_for_threshold(int M, double eps) {
148	    if (M <= 1) return 4;
149	    if (eps < 1e-9) return std::max(4, M);
150	
151	    // Use K=3.0 formula (proven to work well)
152	    double K = 3.0;
153	    double L_needed = K * K * (double)(M - 1) * (M - 1) * eps * (1.0 - eps);
154	    double discriminant = 1.0 + 8.0 * L_needed;
155	    int N_candidate;
156	    if (discriminant >= 0) {
157	        N_candidate = (int)std::ceil((1.0 + std::sqrt(discriminant)) / 2.0);
158	    } else {
159	        N_candidate = 100;
160	    }
161	    // Ensure N >= M for threshold construction
162	    N_candidate = std::max(N_candidate, M);
163	    return std::max(4, std::min(100, N_candidate));
164	}
