void mask_to_adj_matrix_small_N(uint16_t mask, int N_nodes, bool adj_matrix[][N_MAX_GED_CAP]) {
    int bit_idx = 0;
    for (int i = 0; i < N_nodes; ++i) {
        adj_matrix[i][i] = false;
        for (int j = i + 1; j < N_nodes; ++j) {
            adj_matrix[i][j] = adj_matrix[j][i] = ((mask >> bit_idx) & 1);
            bit_idx++;
