        while ((int)chosen.size() < M_graphs && (int)chosen.size() < num_isos) {
            int best = -1, best_dist = -1;
            for (int c = 0; c < num_isos; ++c) {
                if (is_chosen[c]) continue;
                int md = L_ACTUAL + 1;
                for (int ch : chosen) md = std::min(md, pairwise_ged[c][ch]);
                if (md > best_dist) { best_dist = md; best = c; }
            }
            if (best == -1) break;
            chosen.push_back(best);
            is_chosen[best] = true;
        }
        while ((int)chosen.size() < M_graphs) chosen.push_back(chosen[0]);

        G_ADJS_CHOSEN_GED.resize(M_graphs);
        for (int k = 0; k < M_graphs; ++k) {
            uint16_t mask = available_masks[chosen[k]];
            bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(mask, N_ACTUAL, tmp);
            for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) G_ADJS_CHOSEN_GED[k][r][c] = tmp[r][c];

            std::string s_out(L_ACTUAL, '0');
            for (int bit = 0; bit < L_ACTUAL; ++bit)
                if ((mask >> bit) & 1) s_out[bit] = '1';
            std::cout << s_out << std::endl;
        }

    } else {
        // THRESHOLD_DEGREE strategy
        G_SORTED_DEGREES.resize(M_graphs);
        G_RAW_DEGREES.resize(M_graphs);
        G_ADJ_LARGE.resize(M_graphs, std::vector<std::vector<bool>>(N_ACTUAL, std::vector<bool>(N_ACTUAL, false)));
        G_DEGREE_ORDER_LARGE.resize(M_graphs);

        for (int k = 0; k < M_graphs; ++k) {
            std::string s_out(L_ACTUAL, '0');
            std::vector<int> degrees(N_ACTUAL, 0);

            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    bool has_edge = (i < k) || (j < k);
                    if (has_edge) {
                        s_out[idx] = '1';
                        G_ADJ_LARGE[k][i][j] = true;
                        G_ADJ_LARGE[k][j][i] = true;
                        degrees[i]++;
                        degrees[j]++;
                    }
                    idx++;
                }
            }

            G_RAW_DEGREES[k] = degrees;
            G_DEGREE_ORDER_LARGE[k].resize(N_ACTUAL);
            std::iota(G_DEGREE_ORDER_LARGE[k].begin(), G_DEGREE_ORDER_LARGE[k].end(), 0);
            std::sort(G_DEGREE_ORDER_LARGE[k].begin(), G_DEGREE_ORDER_LARGE[k].end(),
                [&](int a, int b) {
                    if (degrees[a] != degrees[b]) return degrees[a] > degrees[b];
                    return a < b;
                });

            G_SORTED_DEGREES[k] = degrees;
            std::sort(G_SORTED_DEGREES[k].begin(), G_SORTED_DEGREES[k].end(), std::greater<int>());

            std::cout << s_out << std::endl;
        }
    }
    std::cout.flush();

    // Query phase
    double time_budget_per_query = 4.5 / 100.0; // 4.5 seconds total for 100 queries

    for (int q = 0; q < 100; ++q) {
        std::string h_str;
        std::cin >> h_str;

        auto query_start = std::chrono::high_resolution_clock::now();

        if (current_strategy == Strategy::GED) {
            string_to_adj_matrix_query(h_str, N_ACTUAL);
            int best_g = 0, min_dist = L_ACTUAL + 1;
            for (int j = 0; j < M_graphs; ++j) {
                int d = min_edit_distance(G_ADJS_CHOSEN_GED[j]);
                if (d < min_dist) { min_dist = d; best_g = j; }
            }
            std::cout << best_g << std::endl;
        } else {
            // THRESHOLD_DEGREE with 2-opt local search
            string_to_adj_matrix_query(h_str, N_ACTUAL);

            std::vector<int> h_degrees(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) { h_degrees[i]++; h_degrees[j]++; }

            // Sort H vertices by degree descending
            std::vector<int> h_degree_order(N_ACTUAL);
            std::iota(h_degree_order.begin(), h_degree_order.end(), 0);
            std::sort(h_degree_order.begin(), h_degree_order.end(),
                [&](int a, int b) {
                    if (h_degrees[a] != h_degrees[b]) return h_degrees[a] > h_degrees[b];
                    return a < b;
                });

            // Sorted degree L2 for candidate selection
            std::vector<int> h_sorted_degrees = h_degrees;
            std::sort(h_sorted_degrees.begin(), h_sorted_degrees.end(), std::greater<int>());

            double scale = 1.0 - 2.0 * eps;
            double offset = (N_ACTUAL - 1) * eps;

            std::vector<std::pair<double, int>> candidates;
            for (int j = 0; j < M_graphs; ++j) {
                double dist = 0.0;
                for (int i = 0; i < N_ACTUAL; ++i) {
                    double expected = G_SORTED_DEGREES[j][i] * scale + offset;
                    double diff = h_sorted_degrees[i] - expected;
                    dist += diff * diff;
                }
                candidates.push_back({dist, j});
            }
            std::sort(candidates.begin(), candidates.end());

            // Refine top candidates with degree-rank alignment + 2-opt local search
            int num_detailed = std::min((int)candidates.size(), 5);
            int best_g = candidates[0].second;
            int min_edge_diff = L_ACTUAL + 1;

            for (int c = 0; c < num_detailed; ++c) {
                int j = candidates[c].second;
                const auto& g_order = G_DEGREE_ORDER_LARGE[j];

                // Initial alignment: degree-rank mapping
                std::vector<int> mapping(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r) {
                    mapping[h_degree_order[r]] = g_order[r];
                }

                int diff = compute_edge_diff(mapping, j);

                // 2-opt local search
                diff = local_search_2opt(mapping, j, diff, 5);

                if (diff < min_edge_diff) {
                    min_edge_diff = diff;
                    best_g = j;
                }

                // Time check
                auto now = std::chrono::high_resolution_clock::now();
                double elapsed = std::chrono::duration<double>(now - query_start).count();
                if (elapsed > time_budget_per_query * 0.8) break;
            }

            std::cout << best_g << std::endl;
        }
        std::cout.flush();
    }
    return 0;
}
