51	void mask_to_adj_matrix_small_N(uint16_t mask, int N_nodes, bool adj_matrix[][N_MAX_GED_CAP]) {
52	    int bit_idx = 0;
53	    for (int i = 0; i < N_nodes; ++i) {
54	        adj_matrix[i][i] = false;
55	        for (int j = i + 1; j < N_nodes; ++j) {
56	            adj_matrix[i][j] = adj_matrix[j][i] = ((mask >> bit_idx) & 1);
57	            bit_idx++;
58	        }
59	    }
60	}
61	
62	uint16_t adj_matrix_to_mask_small_N(int N_nodes, const bool adj_matrix[][N_MAX_GED_CAP], const std::vector<int>& p_perm) {
63	    uint16_t mask = 0;
64	    int bit_idx = 0;
65	    for (int i = 0; i < N_nodes; ++i) {
66	        for (int j = i + 1; j < N_nodes; ++j) {
67	            if (adj_matrix[p_perm[i]][p_perm[j]]) {
68	                mask |= (1U << bit_idx);
69	            }
70	            bit_idx++;
71	        }
72	    }
73	    return mask;
74	}
