147	// Compute the change in edge-diff when swapping assignments of h-vertices u and v
148	// This is O(N) instead of O(N^2) for the full recomputation
149	int compute_swap_delta(const std::vector<int>& mapping, int g_idx, int u, int v) {
150	    const auto& g_adj = G_ADJ_LARGE[g_idx];
151	    int delta = 0;
152	    int gu = mapping[u];
153	    int gv = mapping[v];
154	
155	    for (int w = 0; w < N_ACTUAL; ++w) {
156	        if (w == u || w == v) continue;
157	        int gw = mapping[w];
158	
159	        // Edge (u, w): currently mapped to (gu, gw), after swap mapped to (gv, gw)
160	        bool h_uw = CURRENT_GRAPH_ADJ_QUERY[u][w];
161	        bool g_old_uw = g_adj[gu][gw];
162	        bool g_new_uw = g_adj[gv][gw];
163	        if (h_uw != g_old_uw) delta--; // was a mismatch, removing it
164	        if (h_uw != g_new_uw) delta++; // new mismatch
165	
166	        // Edge (v, w): currently mapped to (gv, gw), after swap mapped to (gu, gw)
167	        bool h_vw = CURRENT_GRAPH_ADJ_QUERY[v][w];
168	        bool g_old_vw = g_adj[gv][gw];
169	        bool g_new_vw = g_adj[gu][gw];
170	        if (h_vw != g_old_vw) delta--;
171	        if (h_vw != g_new_vw) delta++;
172	    }
173	
174	    // Edge (u, v): mapped to (gu, gv) before and (gv, gu) after — same edge, no change
175	    return delta;
176	}
