178	// 2-opt local search: iteratively swap vertex assignments to reduce edge-diff
179	int local_search_2opt(std::vector<int>& mapping, int g_idx, int current_diff, int max_iters) {
180	    bool improved = true;
181	    int iters = 0;
182	    while (improved && iters < max_iters) {
183	        improved = false;
184	        iters++;
185	        for (int u = 0; u < N_ACTUAL - 1 && !improved; ++u) {
186	            for (int v = u + 1; v < N_ACTUAL; ++v) {
187	                int delta = compute_swap_delta(mapping, g_idx, u, v);
188	                if (delta < 0) {
189	                    std::swap(mapping[u], mapping[v]);
190	                    current_diff += delta;
191	                    improved = true;
192	                    break;
193	                }
194	            }
195	        }
196	    }
197	    return current_diff;
198	}
