200	int compute_N_for_threshold(int M, double eps) {
201	    if (M <= 1) return 4;
202	    if (eps < 1e-9) return std::max(4, M);
203	
204	    double K = 3.0;
205	    double L_needed = K * K * (double)(M - 1) * (M - 1) * eps * (1.0 - eps);
206	    double discriminant = 1.0 + 8.0 * L_needed;
207	    int N_candidate;
208	    if (discriminant >= 0) {
209	        N_candidate = (int)std::ceil((1.0 + std::sqrt(discriminant)) / 2.0);
210	    } else {
211	        N_candidate = 100;
212	    }
213	    N_candidate = std::max(N_candidate, M);
214	    return std::max(4, std::min(100, N_candidate));
215	}
