void string_to_adj_matrix_query(const std::string& s, int N_nodes) {
    int char_idx = 0;
    for(int i = 0; i < N_nodes; ++i) {
        CURRENT_GRAPH_ADJ_QUERY[i][i] = false;
        for(int j = i + 1; j < N_nodes; ++j) {
            if (char_idx < (int)s.length()) {
                CURRENT_GRAPH_ADJ_QUERY[i][j] = CURRENT_GRAPH_ADJ_QUERY[j][i] = (s[char_idx++] == '1');
            } else {
                CURRENT_GRAPH_ADJ_QUERY[i][j] = CURRENT_GRAPH_ADJ_QUERY[j][i] = false;
            }
        }
    }
}

// Compute edge difference for a given vertex mapping (h_vertex -> g_vertex)
int compute_edge_diff(const std::vector<int>& mapping, int g_idx) {
    const auto& g_adj = G_ADJ_LARGE[g_idx];
    int diff = 0;
    for (int i = 0; i < N_ACTUAL; ++i) {
        for (int j = i + 1; j < N_ACTUAL; ++j) {
            if (CURRENT_GRAPH_ADJ_QUERY[i][j] != g_adj[mapping[i]][mapping[j]]) diff++;
        }
    }
    return diff;
}

// Compute the change in edge-diff when swapping assignments of h-vertices u and v
// This is O(N) instead of O(N^2) for the full recomputation
int compute_swap_delta(const std::vector<int>& mapping, int g_idx, int u, int v) {
    const auto& g_adj = G_ADJ_LARGE[g_idx];
    int delta = 0;
    int gu = mapping[u];
    int gv = mapping[v];

    for (int w = 0; w < N_ACTUAL; ++w) {
        if (w == u || w == v) continue;
        int gw = mapping[w];

        // Edge (u, w): currently mapped to (gu, gw), after swap mapped to (gv, gw)
        bool h_uw = CURRENT_GRAPH_ADJ_QUERY[u][w];
        bool g_old_uw = g_adj[gu][gw];
        bool g_new_uw = g_adj[gv][gw];
        if (h_uw != g_old_uw) delta--; // was a mismatch, removing it
        if (h_uw != g_new_uw) delta++; // new mismatch

        // Edge (v, w): currently mapped to (gv, gw), after swap mapped to (gu, gw)
        bool h_vw = CURRENT_GRAPH_ADJ_QUERY[v][w];
        bool g_old_vw = g_adj[gv][gw];
        bool g_new_vw = g_adj[gu][gw];
        if (h_vw != g_old_vw) delta--;
        if (h_vw != g_new_vw) delta++;
    }

    // Edge (u, v): mapped to (gu, gv) before and (gv, gu) after — same edge, no change
    return delta;
}

// 2-opt local search: iteratively swap vertex assignments to reduce edge-diff
int local_search_2opt(std::vector<int>& mapping, int g_idx, int current_diff, int max_iters) {
    bool improved = true;
    int iters = 0;
    while (improved && iters < max_iters) {
        improved = false;
        iters++;
        for (int u = 0; u < N_ACTUAL - 1 && !improved; ++u) {
            for (int v = u + 1; v < N_ACTUAL; ++v) {
                int delta = compute_swap_delta(mapping, g_idx, u, v);
                if (delta < 0) {
                    std::swap(mapping[u], mapping[v]);
                    current_diff += delta;
                    improved = true;
                    break;
                }
            }
        }
    }
    return current_diff;
}

int compute_N_for_threshold(int M, double eps) {
    if (M <= 1) return 4;
    if (eps < 1e-9) return std::max(4, M);

    double K = 3.0;
    double L_needed = K * K * (double)(M - 1) * (M - 1) * eps * (1.0 - eps);
    double discriminant = 1.0 + 8.0 * L_needed;
    int N_candidate;
    if (discriminant >= 0) {
        N_candidate = (int)std::ceil((1.0 + std::sqrt(discriminant)) / 2.0);
    } else {
        N_candidate = 100;
    }
    N_candidate = std::max(N_candidate, M);
    return std::max(4, std::min(100, N_candidate));
}

