            }
            available_masks.assign(unique_set.begin(), unique_set.end());
        }

        int num_isos = available_masks.size();
        std::map<uint16_t, int> mask_idx;
        for(int i = 0; i < num_isos; ++i) mask_idx[available_masks[i]] = i;

        std::vector<std::vector<int>> pairwise_ged(num_isos, std::vector<int>(num_isos, 0));
        std::array<std::array<bool, N_MAX_GED_CAP>, N_MAX_GED_CAP> g_j_adj;

        for (int i = 0; i < num_isos; ++i) {
            bool g_i_adj[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(available_masks[i], N_ACTUAL, g_i_adj);
            for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) CURRENT_GRAPH_ADJ_QUERY[r][c] = g_i_adj[r][c];

            for (int j = i + 1; j < num_isos; ++j) {
                bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
                mask_to_adj_matrix_small_N(available_masks[j], N_ACTUAL, tmp);
                for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) g_j_adj[r][c] = tmp[r][c];
                pairwise_ged[i][j] = pairwise_ged[j][i] = min_edit_distance(g_j_adj);
            }
        }

        std::vector<int> chosen;
        std::vector<bool> is_chosen(num_isos, false);

        if (mask_idx.count(0)) {
            chosen.push_back(mask_idx[0]);
            is_chosen[mask_idx[0]] = true;
        }
        uint16_t complete = (L_ACTUAL > 0) ? ((1U << L_ACTUAL) - 1) : 0;
        uint16_t canon_complete = get_canonical_mask(complete);
        if ((int)chosen.size() < M_graphs && mask_idx.count(canon_complete)) {
            int idx = mask_idx[canon_complete];
            if (!is_chosen[idx]) {
                chosen.push_back(idx);
                is_chosen[idx] = true;
