            mask_to_adj_matrix_small_N(mask, N_ACTUAL, tmp);
            for(int r=0; r<N_ACTUAL; ++r) for(int c=0; c<N_ACTUAL; ++c) G_ADJS_CHOSEN_GED[k][r][c] = tmp[r][c];

            std::string s_out(L_ACTUAL, '0');
            for (int bit = 0; bit < L_ACTUAL; ++bit)
                if ((mask >> bit) & 1) s_out[bit] = '1';
            std::cout << s_out << std::endl;
        }

    } else {
        // THRESHOLD_DEGREE strategy
        G_SORTED_DEGREES.resize(M_graphs);
        G_RAW_DEGREES.resize(M_graphs);
        G_ADJ_LARGE.resize(M_graphs, std::vector<std::vector<bool>>(N_ACTUAL, std::vector<bool>(N_ACTUAL, false)));
        G_DEGREE_ORDER_LARGE.resize(M_graphs);

        for (int k = 0; k < M_graphs; ++k) {
            std::string s_out(L_ACTUAL, '0');
            std::vector<int> degrees(N_ACTUAL, 0);

            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    bool has_edge = (i < k) || (j < k);
                    if (has_edge) {
                        s_out[idx] = '1';
                        G_ADJ_LARGE[k][i][j] = true;
                        G_ADJ_LARGE[k][j][i] = true;
                        degrees[i]++;
                        degrees[j]++;
                    }
                    idx++;
                }
            }

            G_RAW_DEGREES[k] = degrees;
            G_DEGREE_ORDER_LARGE[k].resize(N_ACTUAL);
            std::iota(G_DEGREE_ORDER_LARGE[k].begin(), G_DEGREE_ORDER_LARGE[k].end(), 0);
            std::sort(G_DEGREE_ORDER_LARGE[k].begin(), G_DEGREE_ORDER_LARGE[k].end(),
                [&](int a, int b) {
                    if (degrees[a] != degrees[b]) return degrees[a] > degrees[b];
                    return a < b;
                });

            G_SORTED_DEGREES[k] = degrees;
            std::sort(G_SORTED_DEGREES[k].begin(), G_SORTED_DEGREES[k].end(), std::greater<int>());

            std::cout << s_out << std::endl;
        }
    }
    std::cout.flush();

    // Query phase
    double time_budget_per_query = 4.5 / 100.0; // 4.5 seconds total for 100 queries

    for (int q = 0; q < 100; ++q) {
